import{_ as t,o as e,c as i,a3 as s}from"./chunks/framework.CGpxwYOt.js";const h=JSON.parse('{"title":"1.5 巡山与野种","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 巡山指的是在野外地图（多为山间）到处闲逛，意图寻找到野外的公共资源和玩家野种的资源的行为。 可以获得其他玩家野种的资源。获得各种果实和原木。甚至是雷击木（概率极低）。 但是当野外的资源依旧","frontmatter":{"title":"1.5 巡山与野种","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 巡山指的是在野外地图（多为山间）到处闲逛，意图寻找到野外的公共资源和玩家野种的资源的行为。 可以获得其他玩家野种的资源。获得各种果实和原木。甚至是雷击木（概率极低）。 但是当野外的资源依旧","outline":"deep"},"headers":[],"relativePath":"life/1-5.md","filePath":"life/1-5.md","lastUpdated":1782387794000}'),l={name:"life/1-5.md"};function o(r,a,d,u,g,p){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="_1-5-巡山与野种" tabindex="-1">1.5 巡山与野种 <a id="s074-fc41a191"></a> <a class="header-anchor" href="#_1-5-巡山与野种" aria-label="Permalink to &quot;1.5 巡山与野种 &lt;a id=&quot;s074-fc41a191&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-5-1-巡山是什么" tabindex="-1">1.5.1 巡山是什么 <a id="s075-d8761e5f"></a> <a class="header-anchor" href="#_1-5-1-巡山是什么" aria-label="Permalink to &quot;1.5.1 巡山是什么 &lt;a id=&quot;s075-d8761e5f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>巡山指的是在野外地图（多为山间）到处闲逛，意图寻找到野外的公共资源和玩家野种的资源的行为。</p><h2 id="_1-5-2-巡山的收益" tabindex="-1">1.5.2 巡山的收益 <a id="s076-a6b812d1"></a> <a class="header-anchor" href="#_1-5-2-巡山的收益" aria-label="Permalink to &quot;1.5.2 巡山的收益 &lt;a id=&quot;s076-a6b812d1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>可以获得其他玩家野种的资源。获得各种果实和原木。甚至是雷击木（概率极低）。</p><p>但是当野外的资源依旧显示主人名字时，采集这些资源会产生脚印，脚印被别的人玩家举报后会产生罪恶。当然你也可以用道具消除你的脚印。</p><p>道具可以在杂货商人处购买，消除一个脚印要5 个道具。</p><p>道具如下：</p><h2 id="_1-5-3-我需不需要巡山" tabindex="-1">1.5.3 我需不需要巡山？ <a id="s077-fdee9bc1"></a> <a class="header-anchor" href="#_1-5-3-我需不需要巡山" aria-label="Permalink to &quot;1.5.3 我需不需要巡山？ &lt;a id=&quot;s077-fdee9bc1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>如果你恰巧缺少某种果实，且知道在那篇区域刷新，或者知道那有野种的就可以去巡山，否则一般情况下不建议巡山，收益不是很大。当然你除了劳动力一无所有的话，巡山还是很适合你的。</p><h2 id="_1-5-4-野种是什么" tabindex="-1">1.5.4 野种是什么 <a id="s078-f83b676b"></a> <a class="header-anchor" href="#_1-5-4-野种是什么" aria-label="Permalink to &quot;1.5.4 野种是什么 &lt;a id=&quot;s078-f83b676b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>野种指的是将种子或者种子捆在野外（非菜地）进行种植的行为。</p><p>野种主要推荐果树，尤其是生长时间长，占地面积大，容易死亡的果树。</p><h2 id="_1-5-5-野种的成本与收益" tabindex="-1">1.5.5 野种的成本与收益 <a id="s079-e3613019"></a> <a class="header-anchor" href="#_1-5-5-野种的成本与收益" aria-label="Permalink to &quot;1.5.5 野种的成本与收益 &lt;a id=&quot;s079-e3613019&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>使用少许劳动力将占地面积巨大的东西种植在野外，节约了土地占有成本。</p><p>不过当今版本野种存在数量上限，一个账号为100 个单位。</p><h2 id="_1-5-6野种的注意事项" tabindex="-1">1.5.6野种的注意事项 <a id="s080-589d00e4"></a> <a class="header-anchor" href="#_1-5-6野种的注意事项" aria-label="Permalink to &quot;1.5.6野种的注意事项 &lt;a id=&quot;s080-589d00e4&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>野种最好种植主线活动区域视野刷新范围以外，这样子可以最大程度的避免被偷东西和避免被砍伐树木。</p><h2 id="_1-5-7-庭院摘花" tabindex="-1">1.5.7 庭院摘花 <a id="s081-ce52a0d5"></a> <a class="header-anchor" href="#_1-5-7-庭院摘花" aria-label="Permalink to &quot;1.5.7 庭院摘花 &lt;a id=&quot;s081-ce52a0d5&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>庭院摘花可以获得庭院侦查分数和以下道具：</p><figure class="image-flow" data-pdf-anchor="庭院摘花可以获得庭院侦查分数和以下道具："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1188.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="庭院摘花可以获得庭院侦查分数和以下道具："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1189.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="庭院摘花可以获得庭院侦查分数和以下道具："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1190.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="庭院摘花可以获得庭院侦查分数和以下道具："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1191.jpeg" alt="图示" loading="lazy"></figure><p>在下图对应颜色框内可以大量采集对应颜色的花：</p><figure class="image-flow" data-pdf-anchor="在下图对应颜色框内可以大量采集对应颜色的花："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1192.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="道具如下："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1172.jpeg" alt="图示" loading="lazy"></figure>',28)])])}const f=t(l,[["render",o]]);export{h as __pageData,f as default};
